def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a + 4):
                    priority += ((ratio - a) ** 6) / (a * b * 1.1 + 1) * np.tanh(ratio * b / (a + 1))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            if i % 2 == 0:
                priority *= np.sin(ratio * i * 1.05)
            else:
                priority /= np.cos(ratio * i * 1.05) + 1.5
        elif 5 < ratio <= 8:
            for c in range(2, int(np.ceil(ratio)) + 4):
                for d in range(1, c+3):
                    term = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.7)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 2.5
            if bin_cap < item * 0.8:
                priority += np.sqrt(item) * np.log(bin_cap + 2) * 2
        elif 2 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2) * np.cos(r * ratio * 1.1)
            for r2 in range(1, 8):
                s2 += ((5 - ratio) ** r2) / (r2 * 1.5) * np.sin(r2 * ratio * 0.9)
            priority = (s1 * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2 + s2 * 0.7
            if (i + int(item*2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5)
        elif 1.2 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                inner = ((2 - ratio) ** n) / (n ** 2 + 0.3) + np.sin(n * ratio * 3)
                s += inner * np.exp(-n / (ratio + 0.1))
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1.2) ** m) / m
        elif 0.5 <= ratio < 1.2:
            s = 0
            for p in range(1, 18):
                s += ((1.2 - ratio) ** p) / (p * 3.5) * np.cos(p * item * 1.5)
            priority = s
            if (i * int(item * 1.7)) % 6 == 0:
                priority *= np.log1p(bin_cap + 8) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for q in range(1, 8):
                priority += ((1.2 - ratio) ** q) * np.sin(q * item * 1.8) * 0.8
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.7)
            priority = s + 1 / (bin_cap + 5)
            if (int(item * 1.6) + i) % 5 == 0:
                priority *= 2.8
            else:
                priority /= 3.2
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.6) * 3.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 0.95)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        priorities[i] = priority
    return priorities
